/// <summary>
/// Secure value wrapper that prevents memory manipulation/scanning.
/// Stores values encrypted in memory with integrity checks.
/// </summary>
[Serializable]
public struct SecureInt
{
    private int _offset;
    private int _encryptedValue;
    private int _checksum;

    private static readonly int GlobalSalt = UnityEngine.Random.Range(int.MinValue, int.MaxValue);

    public SecureInt(int value)
    {
        _offset = UnityEngine.Random.Range(-100000, 100000);
        _encryptedValue = value + _offset;
        _checksum = ComputeChecksum(value, _offset);
    }

    public int Value
    {
        get
        {
            int decrypted = _encryptedValue - _offset;
            if (_checksum != ComputeChecksum(decrypted, _offset))
            {
                OnTamperDetected();
                return 0;
            }
            return decrypted;
        }
        set
        {
            _offset = UnityEngine.Random.Range(-100000, 100000);
            _encryptedValue = value + _offset;
            _checksum = ComputeChecksum(value, _offset);
        }
    }

    private static int ComputeChecksum(int value, int offset)
    {
        return (value ^ GlobalSalt) * 31 + (offset ^ 0x5A5A5A5A);
    }

    private void OnTamperDetected()
    {
        Debug.LogError("[SECURITY] Memory tampering detected on SecureInt!");
        AntiTamperSystem.Instance?.ReportTamper("SecureInt");
    }

    public static implicit operator int(SecureInt s) => s.Value;
    public static implicit operator SecureInt(int v) => new SecureInt(v);

    public override string ToString() => Value.ToString();
}

