    private int _tamperCount = 0;
    private const int MaxTamperBeforeLockout = 3;

    public event Action OnTamperLockout;

    public bool IsLockedOut { get; private set; }

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }
        Instance = this;
        DontDestroyOnLoad(gameObject);
    }

    public void ReportTamper(string source)
    {
        _tamperCount++;
        Debug.LogWarning($"[SECURITY] Tamper report #{_tamperCount} from {source}");

        if (_tamperCount >= MaxTamperBeforeLockout)
        {
            IsLockedOut = true;
            OnTamperLockout?.Invoke();
            Debug.LogError("[SECURITY] Lockout triggered due to repeated tampering.");
        }
    }
}

