/// <summary>
/// Damage calculation with server-style validation on client.
/// Uses deterministic seeded calculations to detect manipulation.
/// </summary>
public static class DamageCalculator
{
    private static SecureInt _damageNonce = new SecureInt(0);

    [Serializable]
    public struct DamageResult
    {
        public int finalDamage;
        public bool isCritical;
        public int validationToken;
    }

    public static DamageResult CalculateDamage(int attackPower, int targetDefense, float critChance, int seed)
    {
        _damageNonce.Value = _damageNonce.Value + 1;

        // Deterministic RNG based on seed for reproducibility/validation
        System.Random rng = new System.Random(seed ^ _damageNonce.Value);

        int baseDamage = Mathf.Max(1, attackPower - targetDefense / 2);

        // Variance: ±15%
        float variance = 0.85f + (float)rng.NextDouble() * 0.30f;
        int damage = Mathf.RoundToInt(baseDamage * variance);

        bool isCrit = (float)rng.NextDouble() < critChance;
        if (isCrit)
        {
            damage = Mathf.RoundToInt(damage * 2.0f);
        }

        damage = Mathf.Max(1, damage);

        // Validation token: hash of inputs + output to detect post-calculation tampering
        int token = ComputeDamageToken(attackPower, targetDefense, seed, damage, isCrit);

        return new DamageResult
        {
            finalDamage = damage,
            isCritical = isCrit,
            validationToken = token
        };
    }

    public static bool ValidateDamageResult(DamageResult result, int attackPower, int targetDefense, int seed)
    {
        int expectedToken = ComputeDamageToken(attackPower, targetDefense, seed, result.finalDamage, result.isCritical);
        return expectedToken == result.validationToken;
    }

    private static int ComputeDamageToken(int attack, int defense, int seed, int damage, bool crit)
    {
        unchecked
        {
            int hash = 17;
            hash = hash * 31 + attack;
            hash = hash * 31 + defense;
            hash = hash * 31 + seed;
            hash = hash * 31 + damage;
            hash = hash * 31 + (crit ? 1 : 0);
            hash = hash * 31 + 0x7F3A9B2C; // Obfuscation constant
            return hash;
        }
    }
}

/// <summary>
/// Price calculator with integrity checks.
/// </summary>
public static class PriceCalculator
{
    public static int CalculatePrice(ShopItemData item, int playerLevel, int alreadyOwned)
    {
        if (item == null) return int.MaxValue;

        int price = item.basePrice;

        // Scale price with quantity owned (for consumables bought multiple times)
        if (item.isConsumable && alreadyOwned > 0)
        {
            price = Mathf.RoundToInt(price * (1f + alreadyOwned * 0.1f));
        }

        return Mathf.Max(1, price);
    }

    public static int ComputePriceToken(string itemId, int price)
    {
        unchecked
        {
            int hash = itemId.GetHashCode();
            hash = hash * 31 + price;
            hash = hash ^ 0x4D3C2B1A;
            return hash;
        }
    }
}

