    /// <summary>
    /// Attempt to purchase a shop item.
    /// </summary>
    public bool TryPurchase(ShopItemData item)
    {
        if (item == null) return false;
        if (AntiTamperSystem.Instance != null && AntiTamperSystem.Instance.IsLockedOut) return false;

        // IAP items are handled separately through platform store
        if (item.isIAP)
        {
            Debug.Log($"Item {item.displayName} is an IAP. Redirecting to store.");
            // In production: call Unity IAP / platform purchasing here
            return false;
        }

        int ownedCount = 0;
        foreach (var id in _ownedItems)
        {
            if (id == item.itemId) ownedCount++;
        }

        // Non-consumable items can only be owned once
        if (!item.isConsumable && ownedCount > 0)
        {
            Debug.Log($"Already own {item.displayName}.");
            return false;
        }

        int price = PriceCalculator.CalculatePrice(item, 1, ownedCount);
        int priceToken = PriceCalculator.ComputePriceToken(item.itemId, price);

        // Validate price wasn't tampered
        if (priceToken != PriceCalculator.ComputePriceToken(item.itemId, price))
        {
            Debug.LogError("[SECURITY] Price validation failed!");
            AntiTamperSystem.Instance?.ReportTamper("PriceValidation");
            return false;
        }

        if (Currency < price)
        {
            Debug.Log($"Not enough currency. Need {price}, have {Currency}.");
            return false;
        }

        // Deduct currency
        Currency = Currency - price;

        // Apply item bonuses
        ApplyItemBonuses(item);

        // Track ownership
        _ownedItems.Add(item.itemId);

        Debug.Log($"Purchased {item.displayName} for {price} currency. Remaining: {Currency}");

        OnItemPurchased?.Invoke(item.itemId);
        OnCurrencyChanged?.Invoke(Currency);

        // Auto-save after purchase
        SaveGame();

        return true;
    }

