        if (item == null || !item.isIAP) return;

        ApplyItemBonuses(item);
        _ownedItems.Add(item.itemId);

        Debug.Log($"IAP item {item.displayName} applied successfully.");

        OnItemPurchased?.Invoke(item.itemId);
        SaveGame();
    }

    private void ApplyItemBonuses(ShopItemData item)
    {
        if (item.healthBonus > 0)
        {
            MaxHealth = MaxHealth + item.healthBonus;
            Health = Health + item.healthBonus; // Also heal by the bonus amount
            OnHealthChanged?.Invoke(Health, MaxHealth);
        }

        if (item.attackBonus > 0)
        {
            AttackPower = AttackPower + item.attackBonus;
        }

        if (item.defenseBonus > 0)
        {
            Defense = Defense + item.defenseBonus;
        }

        if (item.critChanceBonus > 0f)
        {
            CritChance = CritChance + item.critChanceBonus;
        }
    }

    public bool OwnsItem(string itemId)
    {
        return _ownedItems.Contains(itemId);
    }

    public int GetOwnedCount(string itemId)
    {
        int count = 0;
        foreach (var id in _ownedItems)
        {
            if (id == itemId) count++;
        }
        return count;
    }

    // --- Save/Load ---

    public void SaveGame()
    {
        var saveData = new PlayerSaveData
        {
            health = Health,
            maxHealth = MaxHealth,
            currency = Currency,
            attackPower = AttackPower,
            defense = Defense,
            critChance = CritChance,
            ownedItems = new List<string>(_ownedItems),
            saveTimestamp = DateTimeOffset.UtcNow.ToUnixTimeSeconds()
        };

        string json = JsonUtility.ToJson(saveData);
        SecureSaveSystem.Save(SaveKey, json);
        Debug.Log("Game saved securely.");
    }

    public bool LoadGame()
    {
        string json = SecureSaveSystem.Load(SaveKey);
        if (string.IsNullOrEmpty(json))
        {
            Debug.Log("No valid save data found.");
            return false;
        }

        try
        {
            var saveData = JsonUtility.FromJson<PlayerSaveData>(json);

            // Validate loaded data sanity
            if (saveData.maxHealth <= 0 || saveData.maxHealth > 999999 ||
                saveData.health < 0 || saveData.health > saveData.maxHealth ||
                saveData.currency < 0 || saveData.currency > 99999999 ||
                saveData.attackPower <= 0 || saveData.attackPower > 999999 ||
                saveData.defense < 0 || saveData.defense > 999999 ||
                saveData.critChance < 0f || saveData.critChance > 1f)
            {
                Debug.LogError("[SECURITY] Loaded save data has invalid values!");
                AntiTamperSystem.Instance?.ReportTamper("SaveDataValidation");
                return false;
            }

            // Validate timestamp isn't in the future (time manipulation check)
            long currentTime = DateTimeOffset.UtcNow.ToUnixTimeSeconds();
            if (saveData.saveTimestamp > currentTime + 60) // 60 second tolerance
            {
                Debug.LogWarning("[SECURITY] Save timestamp is in the future!");
                AntiTamperSystem.Instance?.ReportTamper("SaveTimestamp");
            }

            MaxHealth = saveData.maxHealth;
            Health = saveData.health;
            Currency = saveData.currency;
            AttackPower = saveData.attackPower;
            Defense = saveData.defense;
            CritChance = saveData.critChance;
            _ownedItems = saveData.ownedItems ?? new List<string>();

            Debug.Log("Game loaded successfully.");
            return true;
        }
        catch (Exception e)
        {
            Debug.LogError($"Failed to load save data: {e.Message}");
            return false;
        }
    }

    public void ResetToDefaults()
    {
        SecureSaveSystem.DeleteAll(SaveKey);
        MaxHealth = startingHealth;
        Health = startingHealth;
        Currency = startingCurrency;
        AttackPower = startingAttack;
        Defense = startingDefense;
        CritChance = startingCritChance;
        _ownedItems.Clear();
        Debug.Log("Player stats reset to defaults.");
    }

    private void OnApplicationPause(bool pauseStatus)
    {
        if (pauseStatus)
        {
            SaveGame();
        }
    }

    private void OnApplicationQuit()
    {
        SaveGame();
    }
}

