        // UnityPurchasing.InitiatePurchase(item.iapProductId);
    }

    // Called by IAP callback on successful purchase
    public void OnIAPSuccess(string productId)
    {
        foreach (var item in availableItems)
        {
            if (item.isIAP && item.iapProductId == productId)
            {
                PlayerStats.Instance?.OnIAPPurchaseCompleted(item);
                OnShopUpdated?.Invoke();
                return;
            }
        }
    }
}

/// <summary>
/// Example enemy component demonstrating combat integration.
/// </summary>
public class Enemy : MonoBehaviour
{
    [Header("Enemy Stats")]
    public int attackPower = 15;
    public int defense = 3;
    public int maxHealth = 50;

    private SecureInt _health;

    public bool IsAlive => _health.Value > 0;

    private void Start()
    {
        _health = new SecureInt(maxHealth);
    }

    public void AttackPlayer()
    {
        if (!IsAlive || PlayerStats.Instance == null) return;

        int seed = Environment.TickCount ^ GetInstanceID();
        PlayerStats.Instance.TakeDamage(attackPower, seed);
    }

    public void TakeDamage(DamageCalculator.DamageResult damageResult)
    {
        if (!IsAlive) return;

        _health.Value = Mathf.Max(0, _health.Value - damageResult.finalDamage);

        Debug.Log($"Enemy took {damageResult.finalDamage} damage{(damageResult.isCritical ? " (CRIT!)" : "")}. " +
                  $"Health: {_health.Value}/{maxHealth}");

        if (!IsAlive)
        {
            OnDeath();
        }
    }

    private void OnDeath()
    {
        Debug.Log("Enemy defeated!");
        // Reward player
        int reward = UnityEngine.Random.Range(10, 50);
        PlayerStats.Instance?.AddCurrency(reward);
        Destroy(gameObject, 0.5f);
    }

    // Example: Player attacks this enemy
    public void ReceivePlayerAttack()
    {
        if (PlayerStats.Instance == null) return;

        var result = PlayerStats.Instance.DealDamage(defense);
        TakeDamage(result);
    }
}

/// <summary>
/// Game initialization - ensures required systems are set up.
/// </summary>
public class GameBootstrap : MonoBehaviour
{
    private void Awake()
    {
        // Ensure AntiTamperSystem exists
        if (AntiTamperSystem.Instance == null)
        {
            var go = new GameObject("AntiTamperSystem");
            go.AddComponent<AntiTamperSystem>();
        }

        // Ensure PlayerStats exists
        if (PlayerStats.Instance == null)
        {
            var go = new GameObject("PlayerStats");
            go.AddComponent<PlayerStats>();
        }

        // Subscribe to tamper lockout
        if (AntiTamperSystem.Instance != null)
        {
            AntiTamperSystem.Instance.OnTamperLockout += OnTamperLockout;
        }
    }

    private void OnTamperLockout()
    {
        Debug.LogError("GAME LOCKED: Tampering detected. Please restart the game.");
        // In production: show UI message, disable gameplay, report to analytics
    }
}